import { notFound, redirect } from "next/navigation";
import { updateCompanyAction } from "@/app/dashboard/actions";
import { SubmitButton } from "@/app/dashboard/submit-button";
import { prisma } from "@/lib/prisma";
import { requireSessionUser } from "@/lib/session";
import styles from "../../page.module.css";

function getUserFullName(user: {
  firstName: string | null;
  lastName: string | null;
  name: string | null;
  email: string;
}) {
  return `${user.firstName ?? ""} ${user.lastName ?? ""}`.trim() || user.name || user.email;
}

export default async function CompanyDetailPage(props: {
  params: Promise<{ id: string }>;
}) {
  const { user } = await requireSessionUser();

  if (user.role !== "SUPERADMIN") {
    redirect("/dashboard");
  }

  const { id } = await props.params;

  const company = await prisma.company.findUnique({
    where: { id },
    include: {
      users: {
        where: { role: "COMPANY_ADMIN" },
        orderBy: { createdAt: "asc" },
      },
      employees: {
        orderBy: { createdAt: "desc" },
        take: 8,
      },
      devices: {
        orderBy: { createdAt: "desc" },
        take: 8,
      },
      _count: {
        select: {
          employees: true,
          devices: true,
        },
      },
    },
  });

  if (!company) {
    notFound();
  }

  const companyAdmin = company.users[0] ?? null;

  return (
    <div className={styles.page}>
      <section className={`glass-panel ${styles.heroCard}`}>
        <div>
          <p className={styles.eyebrow}>Firma Detayi</p>
          <h1 className={styles.title}>{company.name}</h1>
          <p className={styles.subtitle}>
            Firma bilgilerini inceleyebilir, iletisim kayitlarini ve firma admini hesabini duzenleyebilirsin.
          </p>
        </div>

        <div className={styles.heroMeta}>
          <div className={styles.rolePill}>{company._count.employees} personel</div>
          <div className={styles.helperText}>{company._count.devices} cihaz kayitli</div>
        </div>
      </section>

      <section className={styles.mainGrid}>
        <div className={styles.primaryColumn}>
          <section className={`glass-panel ${styles.sectionCard}`}>
            <div className={styles.sectionHeader}>
              <div>
                <p className={styles.sectionEyebrow}>Duzenleme</p>
                <h2 className={styles.sectionTitle}>Firma ve Admin Bilgileri</h2>
              </div>
            </div>

            <form action={updateCompanyAction} className={styles.formGrid}>
              <input type="hidden" name="companyId" value={company.id} />
              <input type="hidden" name="adminId" value={companyAdmin?.id ?? ""} />

              <label className={styles.field}>
                <span>Firma Adi</span>
                <input name="companyName" defaultValue={company.name} required />
              </label>

              <label className={styles.field}>
                <span>Yetkili Kisi</span>
                <input name="contactName" defaultValue={company.contactName ?? ""} />
              </label>

              <label className={styles.field}>
                <span>Firma E-postasi</span>
                <input name="contactEmail" type="email" defaultValue={company.contactEmail ?? ""} />
              </label>

              <label className={styles.field}>
                <span>Telefon</span>
                <input name="contactPhone" defaultValue={company.contactPhone ?? ""} />
              </label>

              <label className={`${styles.field} ${styles.fullWidth}`}>
                <span>Adres</span>
                <textarea name="address" rows={4} defaultValue={company.address ?? ""} />
              </label>

              <label className={styles.field}>
                <span>Admin Adi</span>
                <input name="adminFirstName" defaultValue={companyAdmin?.firstName ?? ""} required />
              </label>

              <label className={styles.field}>
                <span>Admin Soyadi</span>
                <input name="adminLastName" defaultValue={companyAdmin?.lastName ?? ""} required />
              </label>

              <label className={styles.field}>
                <span>Admin E-postasi</span>
                <input name="adminEmail" type="email" defaultValue={companyAdmin?.email ?? ""} required />
              </label>

              <label className={styles.field}>
                <span>Yeni Admin Sifresi</span>
                <input
                  name="adminPassword"
                  type="password"
                  placeholder="Degistirmek istemiyorsan bos birak"
                />
              </label>

              <div className={styles.fullWidth}>
                <SubmitButton
                  idleLabel="Degisiklikleri Kaydet"
                  pendingLabel="Kaydediliyor..."
                  className={styles.primaryButton}
                />
              </div>
            </form>
          </section>
        </div>

        <aside className={styles.sideColumn}>
          <section className={`glass-panel ${styles.sectionCard}`}>
            <div className={styles.sectionHeader}>
              <div>
                <p className={styles.sectionEyebrow}>Firma Admini</p>
                <h2 className={styles.sectionTitle}>Yetkili Kullanici</h2>
              </div>
            </div>

            <div className={styles.logList}>
              {companyAdmin ? (
                <article className={styles.logItem}>
                  <div>
                    <p className={styles.logTitle}>{getUserFullName(companyAdmin)}</p>
                    <p className={styles.logMeta}>{companyAdmin.email}</p>
                  </div>
                  <div className={styles.logMetaRight}>
                    <p>Rol</p>
                    <p>Firma Admin</p>
                  </div>
                </article>
              ) : (
                <p className={styles.emptyState}>Bu firma icin henuz admin kullanici yok.</p>
              )}
            </div>
          </section>

          <section className={`glass-panel ${styles.sectionCard}`}>
            <div className={styles.sectionHeader}>
              <div>
                <p className={styles.sectionEyebrow}>Son Personeller</p>
                <h2 className={styles.sectionTitle}>Firma Kadrosu</h2>
              </div>
            </div>

            <div className={styles.logList}>
              {company.employees.length === 0 ? (
                <p className={styles.emptyState}>Bu firmada henuz personel kaydi yok.</p>
              ) : (
                company.employees.map((employee) => (
                  <article key={employee.id} className={styles.logItem}>
                    <div>
                      <p className={styles.logTitle}>
                        {employee.firstName} {employee.lastName}
                      </p>
                      <p className={styles.logMeta}>{employee.department}</p>
                    </div>
                    <div className={styles.logMetaRight}>
                      <p>{employee.email ?? "-"}</p>
                      <p>{employee.allowedRadiusM ? `${employee.allowedRadiusM} m` : "-"}</p>
                    </div>
                  </article>
                ))
              )}
            </div>
          </section>

          <section className={`glass-panel ${styles.sectionCard}`}>
            <div className={styles.sectionHeader}>
              <div>
                <p className={styles.sectionEyebrow}>QR Cihazlari</p>
                <h2 className={styles.sectionTitle}>Kayitli Cihazlar</h2>
              </div>
            </div>

            <div className={styles.logList}>
              {company.devices.length === 0 ? (
                <p className={styles.emptyState}>Bu firmada henuz cihaz kaydi yok.</p>
              ) : (
                company.devices.map((device) => (
                  <article key={device.id} className={styles.logItem}>
                    <div>
                      <p className={styles.logTitle}>{device.name}</p>
                      <p className={styles.logMeta}>{device.secretKey}</p>
                    </div>
                    <div className={styles.logMetaRight}>
                      <p>{device.macAddress ?? "-"}</p>
                      <p>{device.activeQrToken ?? "UUID bekleniyor"}</p>
                    </div>
                  </article>
                ))
              )}
            </div>
          </section>
        </aside>
      </section>
    </div>
  );
}
